/**
 * Dispatch a notification payload to the appropriate adapter.
 * Checks user preferences before sending. Records the notification and its delivery result.
 * Notifications to the same recipient are queued and processed in order.
 */
async dispatch(payload: NotificationPayload): Promise<NotificationResult> {
  const recipient = payload.recipient;
  const previousInQueue = this.recipientQueues.get(recipient) ?? Promise.resolve(undefined as unknown as NotificationResult);

  const resultPromise = previousInQueue
    .catch(() => {}) // Don't let a failed previous notification block the queue
    .then(() => this.dispatchImmediate(payload));

  this.recipientQueues.set(recipient, resultPromise);

  // Clean up the queue entry when this is the last item
  resultPromise.finally(() => {
    if (this.recipientQueues.get(recipient) === resultPromise) {
      this.recipientQueues.delete(recipient);
    }
  });

  return resultPromise;
}

