  describe('notification ordering', () => {
    it('should deliver notifications to the same recipient in dispatch order even when adapter is slow', async () => {
      const deliveryOrder: string[] = [];

      // Adapter with variable delay — first call is slow, second is fast
      let callCount = 0;
      const slowAdapter: NotificationAdapter = {
        channel: 'email' as NotificationChannel,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          callCount++;
          const delay = callCount === 1 ? 50 : 5; // first notification is slow
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.type);
          return { success: true, notificationId: '', channel: 'email' };
        },
      };

      // Replace adapter with slow one
      service.registerAdapter(slowAdapter);

      // Dispatch two notifications concurrently to the same recipient
      const promise1 = service.dispatch({
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order has been placed',
        channel: 'email',
        type: 'order_confirmation',
      });
      const promise2 = service.dispatch({
        recipient: 'alice@example.com',
        subject: 'Order Confirmed',
        body: 'Your order has been confirmed',
        channel: 'email',
        type: 'order_status_update',
      });

      await Promise.all([promise1, promise2]);

      // Despite the first adapter call being slower, order_confirmation must come first
      expect(deliveryOrder).toEqual(['order_confirmation', 'order_status_update']);

      // Notifications array should also be in order
      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(2);
      expect(notifications[0]?.type).toBe('order_confirmation');
      expect(notifications[1]?.type).toBe('order_status_update');
    });

    it('should not block notifications for different recipients', async () => {
      const deliveryOrder: string[] = [];

      let callCount = 0;
      const slowAdapter: NotificationAdapter = {
        channel: 'email' as NotificationChannel,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          callCount++;
          const delay = callCount === 1 ? 50 : 5;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(`${payload.recipient}:${payload.type}`);
          return { success: true, notificationId: '', channel: 'email' };
        },
      };

      service.registerAdapter(slowAdapter);

      // Dispatch to two different recipients concurrently
      const promise1 = service.dispatch({
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order has been placed',
        channel: 'email',
        type: 'order_confirmation',
      });
      const promise2 = service.dispatch({
        recipient: 'bob@example.com',
        subject: 'Welcome',
        body: 'Welcome!',
        channel: 'email',
        type: 'welcome',
      });

      await Promise.all([promise1, promise2]);

      // Bob's notification should arrive before Alice's since Alice's adapter is slow
      expect(deliveryOrder[0]).toBe('bob@example.com:welcome');
      expect(deliveryOrder[1]).toBe('alice@example.com:order_confirmation');
    });
  });
});

